require "config.JobConfig"

GameJob = class()

function GameJob:ctor(player)
    self.userId = player.userId
    self.allJobs = JobConfig:getJobList()
end

function GameJob:init()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    for i, item in pairs(player.jobs_data) do
        self.allJobs[tonumber(item.id)].status = JobStatus.HAVE
        self.allJobs[tonumber(item.id)].times = tonumber(item.times)
    end
    self:setSelectJob()
    self:synUpdateUIDates(player)
end


--设置默认的选择的职业
function GameJob:setSelectJob()
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end

    if JobConfig:getDefaultJob() == player.lastJobId then
        player.cur_jobId = player.lastJobId
        GamePacketSender:sendCurJobIdData(player.rakssid, player.cur_jobId)
        return
    end
    for _, job in pairs(player.jobs_data) do
        if tonumber(job.id) == tonumber(player.lastJobId) then
            if job.times > 0 then
                player.cur_jobId = player.lastJobId
                GamePacketSender:sendCurJobIdData(player.rakssid, player.cur_jobId)
                return
            end
        end
    end
    for _, job in pairs(player.jobs_data) do
        if job.times > 0 then
            player.cur_jobId = job.id
            GamePacketSender:sendCurJobIdData(player.rakssid, player.cur_jobId)
            return
        end
    end
    player.cur_jobId = JobConfig:getDefaultJob()
    GamePacketSender:sendCurJobIdData(player.rakssid, player.cur_jobId)
end

--更新里面的次数
function GameJob:updateJobUIData(id, times, needSync)
    local player = PlayerManager:getPlayerByUserId(self.userId)
    if not player then
        return
    end
    --若该职业是默认职业
    local type = JobConfig:getJobTypeById(id)
    if type == Define.JobType.DefaultJob then
        return
    end

    for _, job in pairs(player.jobs_data) do
        if tonumber(job.id) == tonumber(id) then
            job.times = job.times + times
            self.allJobs[tonumber(id)].times = self.allJobs[tonumber(id)].times + times

            local data = {}
            local item = {
                id = job.id,
                times = job.times,
                needSync = needSync or false
            }
            table.insert(data, item)
            GamePacketSender:sendUpdateJobChoiceUIData(player.rakssid, json.encode(data))
            return
        end
    end

    if self.allJobs[tonumber(id)] ~= nil then
        local item = {
            id = tonumber(id),
            times = 0
        }
        if times > 0 then
            item.times = times
        end
        self.allJobs[tonumber(id)].time = self.allJobs[tonumber(id)].times + times
        self.allJobs[tonumber(id)].status = JobStatus.HAVE

        local data = {}
        table.insert(data, {
            id = item.id,
            times = item.times
        })
        table.insert(player.jobs_data, item)
        GamePacketSender:sendUpdateJobChoiceUIData(player.rakssid, json.encode(data))
    end
end

--同步所有的职业数据
function GameJob:synUpdateUIDates(player)
    local data = {}
    for _, item in pairs(player.jobs_data) do
        table.insert(data, {
            id = item.id,
            times = item.times
        })
    end
    GamePacketSender:sendUpdateJobChoiceUIData(player.rakssid, json.encode(data))
end

return GameJob